        if (!response.IsSuccessStatusCode) return null;
        return await response.Content.ReadFromJsonAsync<ShipmentDto>();
    }

    public async Task<ShipmentDto?> GetShipmentAsync(int id)
        => await http.GetFromJsonAsync<ShipmentDto>($"api/shipments/{id}");

