@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@attribute [Authorize(Roles = "Customer")]
@inject ShipmentService ShipmentService

<PageTitle>My Shipments</PageTitle>

<h1>📦 My Shipments</h1>

@if (shipments == null)
{
    <p><em>Loading your shipments...</em></p>
}
else if (!shipments.Any())
{
    <div class="alert alert-info">You have no shipments yet.</div>
}
else
{
    <div class="row">
        @foreach (var s in shipments)
        {
            <div class="col-md-6 col-lg-4 mb-3">
                <div class="card h-100 @(s.Status == ShipmentStatus.Delivered ? "border-success" : "")">
                    <div class="card-header d-flex justify-content-between">
                        <code>@s.TrackingNumber</code>
                        <span class="badge @GetStatusBadgeClass(s.Status)">@s.Status</span>
                    </div>
                    <div class="card-body">
                        <p class="mb-1"><strong>From:</strong> @s.Origin</p>
                        <p class="mb-1"><strong>To:</strong> @s.Destination</p>
                        <p class="mb-1"><strong>Recipient:</strong> @s.RecipientName</p>
                        @if (s.EstimatedDelivery.HasValue)
                        {
                            <p class="mb-1"><strong>Est. Delivery:</strong> @s.EstimatedDelivery.Value.ToString("MMM dd, yyyy")</p>
                        }
                        @if (s.ActualDelivery.HasValue)
                        {
                            <p class="mb-1 text-success"><strong>Delivered:</strong> @s.ActualDelivery.Value.ToString("MMM dd, yyyy h:mm tt")</p>
                        }
                        @if (s.Notes != null)
                        {
                            <p class="mb-0 text-muted"><small>@s.Notes</small></p>
                        }
                    </div>
                    <div class="card-footer">
                        <button class="btn btn-sm btn-outline-primary" @onclick="() => ToggleDetails(s.Id)">
                            @(expandedId == s.Id ? "Hide Details" : "Show Details")
                        </button>
                        @if (expandedId == s.Id)
                        {
                            <div class="mt-2">
                                <p class="mb-1"><strong>Created:</strong> @s.CreatedDate.ToString("MMM dd, yyyy h:mm tt")</p>
                                <div class="progress mt-2" style="height: 25px;">
                                    <div class="progress-bar @GetProgressBarClass(s.Status)"
                                         role="progressbar"
                                         style="width: @(GetProgressPercent(s.Status))%">
                                        @s.Status
                                    </div>
                                </div>
                            </div>
                        }
                    </div>
                </div>
            </div>
        }
    </div>
}

<div class="mt-3">
