```csharp
using System.Security.Claims;
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Data;

namespace ShipmentTracker.Endpoints;

public static class ShipmentEndpoints
{
    public static void MapShipmentApi(this WebApplication app)
    {
        var group = app.MapGroup("/api/shipments");

        // All shipments - Dispatcher only
        group.MapGet("/", async (ShipmentTracker.Data.ShipmentStatus? status, ApplicationDbContext db) =>
        {
            var query = db.Shipments.AsQueryable();
            if (status.HasValue)
                query = query.Where(s => s.Status == status.Value);
            var shipments = await query.OrderByDescending(s => s.CreatedDate).ToListAsync();
            return Results.Ok(shipments.Select(ToDto).ToList());
        }).RequireAuthorization(policy => policy.RequireRole("Dispatcher"));

        // My shipments - Customer only
        group.MapGet("/my", async (ClaimsPrincipal user, ApplicationDbContext db) =>
        {
            var userId = user.FindFirstValue(ClaimTypes.NameIdentifier);
            var shipments = await db.Shipments
                .Where(s => s.CustomerUserId == userId)
                .OrderByDescending(s => s.CreatedDate)
                .ToListAsync();
            return Results.Ok(shipments.Select(ToDto).ToList());
        }).RequireAuthorization(policy => policy.RequireRole("Customer"));

        // Track by tracking number - public
        group.MapGet("/track/{trackingNumber}", async (string trackingNumber, ApplicationDbContext db) =>
        {
            var shipment = await db.Shipments.FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
            return shipment is null ? Results.NotFound() : Results.Ok(ToDto(shipment));
        });

        // Get by ID - Dispatcher or owning Customer
        group.MapGet("/{id:int}", async (int id, ClaimsPrincipal user, ApplicationDbContext db) =>
        {
            var shipment = await db.Shipments.FindAsync(id);
            if (shipment is null) return Results.NotFound();

            var isDispatcher = user.IsInRole("Dispatcher");
            var userId = user.FindFirstValue(ClaimTypes.NameIdentifier);
            if (!isDispatcher && shipment.CustomerUserId != userId)
                return Results.Forbid();

            return Results.Ok(ToDto(shipment));
        }).RequireAuthorization();

        // Create - Dispatcher only
        group.MapPost("/", async (ShipmentDto dto, ApplicationDbContext db) =>
        {
            var shipment = new Shipment
            {
                TrackingNumber = $"TRK-{DateTime.UtcNow:yyyyMMdd}-{Random.Shared.Next(100, 999)}",
                Origin = dto.Origin,
                Destination = dto.Destination,
                Status = ShipmentTracker.Data.ShipmentStatus.Pending,
                CreatedDate = DateTime.UtcNow,
                EstimatedDelivery = dto.EstimatedDelivery,
                RecipientName = dto.RecipientName,
                RecipientEmail = dto.RecipientEmail,
                CustomerUserId = dto.CustomerUserId,
                Notes = dto.Notes
            };
            db.Shipments.Add(shipment);
            await db.SaveChangesAsync();
            return Results.Created($"/api/shipments/{shipment.Id}", ToDto(shipment));
        }).RequireAuthorization(policy => policy.RequireRole("Dispatcher"));

        // Update - Dispatcher only
        group.MapPut("/{id:int}", async (int id, ShipmentDto dto, ApplicationDbContext db) =>
        {
            var shipment = await db.Shipments.FindAsync(id);
            if (shipment is null) return Results.NotFound();

            shipment.Status = (ShipmentTracker.Data.ShipmentStatus)(int)dto.Status;
            shipment.Notes = dto.Notes;
            shipment.EstimatedDelivery = dto.EstimatedDelivery;
            if (dto.ActualDelivery.HasValue)
                shipment.ActualDelivery = dto.ActualDelivery;

            await db.SaveChangesAsync();
            return Results.Ok(ToDto(shipment));
        }).RequireAuthorization(policy => policy.RequireRole("Dispatcher"));
    }

    private static ShipmentDto ToDto(Shipment s) => new()
    {
        Id = s.Id,
        TrackingNumber = s.TrackingNumber,
        Origin = s.Origin,
        Destination = s.Destination,
        Status = (ShipmentTracker.Client.Models.ShipmentStatus)(int)s.Status,
        CreatedDate = s.CreatedDate,
        EstimatedDelivery = s.EstimatedDelivery,
        ActualDelivery = s.ActualDelivery,
        RecipientName = s.RecipientName,
        RecipientEmail = s.RecipientEmail,
        CustomerUserId = s.CustomerUserId,
        Notes = s.Notes
    };
}
```

